const https=require\('https'\);
const crypto=require\('crypto'\);

function getHash\(url\){
  return new Promise\(\(resolve,reject\)=>{
    function follow\(u\){
      const parsed=new URL\(u\);
      https.get\({hostname:parsed.hostname,path:parsed.pathname+parsed.search,headers:{'User-Agent':'node'}},res=>{
        if\(res.statusCode===301||res.statusCode===302\){
          const loc=res.headers.location;
          follow\(loc.startsWith\('http'\)?loc:'https://unpkg.com'+loc\);
          return;
        }
        const chunks=[];
        res.on\('data',c=>chunks.push\(c\)\);
        res.on\('end',\(\)=>{
          const buf=Buffer.concat\(chunks\);
          const hash=crypto.createHash\('sha384'\).update\(buf\).digest\('base64'\);
          resolve\({orig:url,resolved:u,sri:'sha384-'+hash}\);
        }\);
        res.on\('error',reject\);
      }\);
    }
    follow\(url\);
  }\);
}

Promise.all\([
  'https://unpkg.com/react@18/umd/react.development.js',
  'https://unpkg.com/react-dom@18/umd/react-dom.development.js',
  'https://unpkg.com/@babel/standalone/babel.min.js',
  'https://unpkg.com/html2canvas@1.4.1/dist/html2canvas.min.js'
].map\(getHash\)\).then\(r=>r.forEach\(x=>console.log\(x.orig+'|'+x.resolved+'|'+x.sri\)\)\).catch\(e=>console.error\(e.message\)\);
" 2>&1)
